return items.map(item => {
  const data = item.json;

  // ── Derive channel and category from type ──────────────────────
  // type format: {channel}_{category}_{nn}
  // e.g. whatsapp_objection_01 → channel=whatsapp, category=objection
  // e.g. email_sevenrooms_05   → channel=email,    category=sevenrooms
  const parts = data.type.split('_');
  const channel = parts[0]; // 'whatsapp' | 'email'
  const lastPart = parts[parts.length - 1];
  const isNumber = /^\d+$/.test(lastPart);
  const category = (isNumber ? parts.slice(1, -1) : parts.slice(1)).join('_');

  // ── Flag rows that contain placeholders (need runtime substitution)
  const hasPlaceholders = /\[[A-Z_]+\]/.test(data.response_sent);

  // ── Build content string for embedding ────────────────────────
  const documentText =
    `Prospect's message: "${data.content}"\n\nHow to respond:\n${data.response_sent}`;

  return {
    json: {
      content: documentText,
      metadata: {
        type:             data.type,
        channel:          channel,      // 'whatsapp' | 'email'
        category:         category,     // 'objection' | 'sevenrooms' | 'nowbookit' | 'referral' | 'general'
        has_placeholders: hasPlaceholders, // true = agent must substitute [COUNTRY] etc.
      }
    }
  };
});

